#include<iostream>
#include<cstdio>
#include<algorithm>
using namespace std;

int dp[2005], v[105], h[105];

int main() {
	int n, t, k;
	cin >> n >> t >> k;
	for(int i = 1; i <= n; i++)
		cin >> v[i] >> h[i];
	for(int i = 1; i <= n; i++)
		for(int j = h[i]; j <= t * 5/4; j++)
			dp[j] = max(dp[j], dp[j - h[i]] + v[i]);
	int ans = dp[t];
	for(int i = 1; i <= n; i++)
	{
		if(h[i] < k) continue;
		int tmp = v[i] + dp[(t - h[i]) * 5/4];
		ans = max(tmp, ans);
	}
	cout << ans;
    return 0;
}
